package assessment.manager.services.implementations;

import assessment.manager.data.models.Assessment;
import assessment.manager.data.models.Option;
import assessment.manager.data.models.Question;
import assessment.manager.data.repositories.AssessmentRepo;
import assessment.manager.data.repositories.OptionRepo;
import assessment.manager.data.repositories.QuestionRepo;
import assessment.manager.dtos.requests.*;
import assessment.manager.dtos.responses.*;
import assessment.manager.exceptions.*;
import assessment.manager.services.interfaces.AssessmentService;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

@Service
@RequiredArgsConstructor
public class AssessmentServiceImpl  implements AssessmentService {
private final AssessmentRepo assessmentRepo;
private final QuestionRepo questionRepo;
private final OptionRepo optionRepo;

    @Override
    public AssessmentResponse createAssessment(CreateAssessmentRequest request) {
        // Validate input request
        validateCreateAssessmentRequest(request);
        
        Assessment assessment = Assessment.builder()
                .id(null)
                .creatorId(request.getCreatorId())
                .title(request.getTitle())
                .description(request.getDescription())
                .questionIds(new ArrayList<>())
                .timerDuration(request.getTimerDuration())
                .isOptionsRandomize(request.isRandomizeOptions())
                .isQuestionsRandomize(request.isRandomizeQuestions())
                .createdAt(LocalDateTime.now())
                .updatedAt(LocalDateTime.now())
                .build();

        Assessment savedAssessment = assessmentRepo.save(assessment);
        return convertToResponse(savedAssessment);
    }

    @Override
    public AssessmentListResponse viewAssessmentsCreated(String creatorId) {
        if (creatorId == null || creatorId.trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Creator ID cannot be null or empty");
        }
        
        try {
            List<Assessment> assessments = assessmentRepo.findByCreatorId(creatorId);
            
            List<AssessmentResponse> assessmentResponses = assessments.stream()
                    .map(this::convertToResponse)
                    .collect(Collectors.toList());
            
            return AssessmentListResponse.builder()
                    .assessments(assessmentResponses)
                    .build();
        } catch (Exception e) {
            throw new AssessmentOperationException("Error fetching assessments for creator: " + creatorId, e);
        }
    }

    @Override
    public GradeResponse autoGrade(AutoGradeRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Grading request cannot be null");
        }
        
        if (request.getAssessmentId() == null || request.getAssessmentId().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Assessment ID cannot be null or empty");
        }
        
        try {
            Assessment assessment = assessmentRepo.findById(request.getAssessmentId())
                    .orElseThrow(() -> new AssessmentNotFoundException("Assessment not found with ID: " + request.getAssessmentId()));
            
            int totalQuestions = assessment.getQuestionIds().size();
            int correctAnswers = 0;
            
            // Grade each answered question
            for (AnsweredQuestionRequest answeredQuestion : request.getAnsweredQuestions()) {
                Question question = getQuestionById(answeredQuestion.getQuestionId());
                
                // Check if the selected answer is correct
                if (question.getCorrectOptionId() != null && 
                    question.getCorrectOptionId().equals(answeredQuestion.getSelectedOptionId())) {
                    correctAnswers++;
                }
            }
            
            // Calculate grade as percentage
            int grade = totalQuestions > 0 ? (correctAnswers * 100) / totalQuestions : 0;
            
            return GradeResponse.builder()
                    .grade(grade)
                    .build();
        } catch (AssessmentNotFoundException e) {
            throw e;
        } catch (Exception e) {
            throw new GradingException("Error grading assessment: " + request.getAssessmentId(), e);
        }
    }

    @Override
    public void setTimer(SetTimerRequest request) {
        try {
            Assessment assessment = assessmentRepo.findById(request.getAssessmentId())
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + request.getAssessmentId()));
            
            // Convert minutes to seconds for storage
            long timerDurationInSeconds = request.getDurationMinutes() * 60;
            
            Assessment updatedAssessment = Assessment.builder()
                    .id(assessment.getId())
                    .creatorId(assessment.getCreatorId())
                    .title(assessment.getTitle())
                    .description(assessment.getDescription())
                    .questionIds(assessment.getQuestionIds())
                    .timerDuration(timerDurationInSeconds)
                    .isOptionsRandomize(assessment.isOptionsRandomize())
                    .isQuestionsRandomize(assessment.isQuestionsRandomize())
                    .createdAt(assessment.getCreatedAt())
                    .updatedAt(LocalDateTime.now())
                    .build();
            
            assessmentRepo.save(updatedAssessment);
        } catch (Exception e) {
            throw new RuntimeException("Error setting timer for assessment: " + request.getAssessmentId(), e);
        }
    }

    @Override
    public void randomizeQuestions(RandomizeQuestionsRequest request) {
        try {
            Assessment assessment = assessmentRepo.findById(request.getAssessmentId())
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + request.getAssessmentId()));
            
            // Toggle question randomization
            Assessment updatedAssessment = Assessment.builder()
                    .id(assessment.getId())
                    .creatorId(assessment.getCreatorId())
                    .title(assessment.getTitle())
                    .description(assessment.getDescription())
                    .questionIds(assessment.getQuestionIds())
                    .timerDuration(assessment.getTimerDuration())
                    .isOptionsRandomize(assessment.isOptionsRandomize())
                    .isQuestionsRandomize(!assessment.isQuestionsRandomize()) // Toggle randomization
                    .createdAt(assessment.getCreatedAt())
                    .updatedAt(LocalDateTime.now())
                    .build();
            
            assessmentRepo.save(updatedAssessment);
        } catch (Exception e) {
            throw new RuntimeException("Error updating question randomization for assessment: " + request.getAssessmentId(), e);
        }
    }

    @Override
    public void randomizeOptions(RandomizeOptionsRequest request) {
        try {
            Assessment assessment = assessmentRepo.findById(request.getAssessmentId())
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + request.getAssessmentId()));
            
            // Toggle option randomization
            Assessment updatedAssessment = Assessment.builder()
                    .id(assessment.getId())
                    .creatorId(assessment.getCreatorId())
                    .title(assessment.getTitle())
                    .description(assessment.getDescription())
                    .questionIds(assessment.getQuestionIds())
                    .timerDuration(assessment.getTimerDuration())
                    .isOptionsRandomize(!assessment.isOptionsRandomize()) // Toggle randomization
                    .isQuestionsRandomize(assessment.isQuestionsRandomize())
                    .createdAt(assessment.getCreatedAt())
                    .updatedAt(LocalDateTime.now())
                    .build();
            
            assessmentRepo.save(updatedAssessment);
        } catch (Exception e) {
            throw new RuntimeException("Error updating option randomization for assessment: " + request.getAssessmentId(), e);
        }
    }

    @Override
    public void setCorrectAnswer(SetCorrectAnswerRequest request) {
        try {
            Question question = getQuestionById(request.getQuestionId());
            
            // Verify that the option exists and belongs to this question
            if (!question.getOptionIds().contains(request.getOptionId())) {
                throw new RuntimeException("Option ID " + request.getOptionId() + 
                    " does not belong to question ID " + request.getQuestionId());
            }
            
            // Verify the option exists in the database
            getOptionById(request.getOptionId());
            
            // Update the question with the correct answer
            Question updatedQuestion = Question.builder()
                    .id(question.getId())
                    .text(question.getText())
                    .optionIds(question.getOptionIds())
                    .correctOptionId(request.getOptionId())
                    .tags(question.getTags())
                    .build();
            
            questionRepo.save(updatedQuestion);
        } catch (Exception e) {
            throw new RuntimeException("Error setting correct answer for question: " + request.getQuestionId(), e);
        }
    }

    @Override
    public QuestionResponse createQuestion(CreateQuestionRequest request) {
        try {
            // Validate input request
            validateCreateQuestionRequest(request);
            
            Question question = Question.builder()
                    .id(null)
                    .text(request.getText())
                    .optionIds(new ArrayList<>())
                    .correctOptionId(null)
                    .tags(request.getTags() != null ? request.getTags() : new ArrayList<>())
                    .build();
            
            Question savedQuestion = questionRepo.save(question);
            return convertToQuestionResponse(savedQuestion);
        } catch (Exception e) {
            throw new RuntimeException("Error creating question", e);
        }
    }

    @Override
    public OptionResponse createOption(CreateOptionRequest request) {
        try {
            // Validate input request
            validateCreateOptionRequest(request);
            
            // Verify the question exists
            Question question = getQuestionById(request.getQuestionId());
            
            // Create the option
            Option option = Option.builder()
                    .id(null)
                    .text(request.getText())
                    .build();
            
            Option savedOption = optionRepo.save(option);
            
            // Add the option to the question
            List<String> updatedOptionIds = new ArrayList<>(question.getOptionIds());
            updatedOptionIds.add(savedOption.getId());
            
            Question updatedQuestion = Question.builder()
                    .id(question.getId())
                    .text(question.getText())
                    .optionIds(updatedOptionIds)
                    .correctOptionId(question.getCorrectOptionId())
                    .tags(question.getTags())
                    .build();
            
            questionRepo.save(updatedQuestion);
            
            return convertToOptionResponse(savedOption);
        } catch (Exception e) {
            throw new RuntimeException("Error creating option for question: " + request.getQuestionId(), e);
        }
    }

    @Override
    public AssessmentResponse updateAssessment(UpdateAssessmentRequest request) {
        try {
            // Validate input request
            validateUpdateAssessmentRequest(request);
            
            // Get existing assessment
            Assessment existingAssessment = assessmentRepo.findById(request.getAssessmentId())
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + request.getAssessmentId()));
            
            // Update assessment
            Assessment updatedAssessment = Assessment.builder()
                    .id(existingAssessment.getId())
                    .creatorId(existingAssessment.getCreatorId())
                    .title(request.getTitle())
                    .description(request.getDescription())
                    .questionIds(existingAssessment.getQuestionIds())
                    .timerDuration(request.getTimerDuration())
                    .isOptionsRandomize(request.isRandomizeOptions())
                    .isQuestionsRandomize(request.isRandomizeQuestions())
                    .createdAt(existingAssessment.getCreatedAt())
                    .updatedAt(LocalDateTime.now())
                    .build();
            
            Assessment savedAssessment = assessmentRepo.save(updatedAssessment);
            return convertToResponse(savedAssessment);
        } catch (Exception e) {
            throw new RuntimeException("Error updating assessment: " + request.getAssessmentId(), e);
        }
    }

    @Override
    public QuestionResponse updateQuestion(UpdateQuestionRequest request) {
        try {
            // Validate input request
            validateUpdateQuestionRequest(request);
            
            // Get existing question
            Question existingQuestion = getQuestionById(request.getQuestionId());
            
            // Update question
            Question updatedQuestion = Question.builder()
                    .id(existingQuestion.getId())
                    .text(request.getText())
                    .optionIds(existingQuestion.getOptionIds())
                    .correctOptionId(existingQuestion.getCorrectOptionId())
                    .tags(request.getTags() != null ? request.getTags() : existingQuestion.getTags())
                    .build();
            
            Question savedQuestion = questionRepo.save(updatedQuestion);
            return convertToQuestionResponse(savedQuestion);
        } catch (Exception e) {
            throw new RuntimeException("Error updating question: " + request.getQuestionId(), e);
        }
    }

    @Override
    public OptionResponse updateOption(UpdateOptionRequest request) {
        try {
            // Validate input request
            validateUpdateOptionRequest(request);
            
            // Get existing option
            Option existingOption = getOptionById(request.getOptionId());
            
            // Update option
            Option updatedOption = Option.builder()
                    .id(existingOption.getId())
                    .text(request.getText())
                    .build();
            
            Option savedOption = optionRepo.save(updatedOption);
            return convertToOptionResponse(savedOption);
        } catch (Exception e) {
            throw new RuntimeException("Error updating option: " + request.getOptionId(), e);
        }
    }

    private AssessmentResponse convertToResponse(Assessment assessment) {
        return AssessmentResponse.builder()
                .id(assessment.getId())
                .creatorId(assessment.getCreatorId())
                .title(assessment.getTitle())
                .description(assessment.getDescription())
                .questions(assessment.getQuestionIds().stream()
                        .map(this::getQuestionById)
                        .map(this::convertToQuestionResponse)
                        .collect(Collectors.toList()))
                .timerDuration(assessment.getTimerDuration())
                .isQuestionsRandomized(assessment.isQuestionsRandomize())
                .isOptionsRandomized(assessment.isOptionsRandomize())
                .createdAt(assessment.getCreatedAt())
                .updatedAt(assessment.getUpdatedAt())
                .build();
    }

    private QuestionResponse convertToQuestionResponse(Question question) {
        return QuestionResponse.builder()
                .id(question.getId())
                .text(question.getText())
                .options(question.getOptionIds().stream()
                        .map(this::getOptionById)
                        .map(this::convertToOptionResponse)
                        .collect(Collectors.toList()))
                .correctOptionId(question.getCorrectOptionId())
                .tags(question.getTags())
                .build();
    }

    private OptionResponse convertToOptionResponse(Option option) {
        return OptionResponse.builder()
                .id(option.getId())
                .text(option.getText())
                .build();
    }

    private Question getQuestionById(String id) {
        return questionRepo.findById(id)
                .orElseThrow(() -> new RuntimeException("Question not found with ID: " + id));
    }

    private Option getOptionById(String id) {
        return optionRepo.findById(id)
                .orElseThrow(() -> new RuntimeException("Option not found with ID: " + id));
    }

    /**
     * Additional utility method to get assessment by ID
     * This can be used by the controller for single assessment retrieval
     */
    public AssessmentResponse getAssessmentById(String assessmentId) {
        try {
            Assessment assessment = assessmentRepo.findById(assessmentId)
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + assessmentId));
            return convertToResponse(assessment);
        } catch (Exception e) {
            throw new RuntimeException("Error fetching assessment: " + assessmentId, e);
        }
    }

    /**
     * Additional utility method to delete assessment by ID
     * This can be used by the controller for assessment deletion
     */
    public void deleteAssessment(String assessmentId) {
        try {
            if (!assessmentRepo.existsById(assessmentId)) {
                throw new RuntimeException("Assessment not found with ID: " + assessmentId);
            }
            assessmentRepo.deleteById(assessmentId);
        } catch (Exception e) {
            throw new RuntimeException("Error deleting assessment: " + assessmentId, e);
        }
    }

    /**
     * Additional utility method to add a question to an assessment
     */
    public void addQuestionToAssessment(String assessmentId, String questionId) {
        try {
            Assessment assessment = assessmentRepo.findById(assessmentId)
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + assessmentId));
            
            // Verify the question exists
            getQuestionById(questionId);
            
            // Add question if not already present
            if (!assessment.getQuestionIds().contains(questionId)) {
                List<String> updatedQuestionIds = new ArrayList<>(assessment.getQuestionIds());
                updatedQuestionIds.add(questionId);
                
                Assessment updatedAssessment = Assessment.builder()
                        .id(assessment.getId())
                        .creatorId(assessment.getCreatorId())
                        .title(assessment.getTitle())
                        .description(assessment.getDescription())
                        .questionIds(updatedQuestionIds)
                        .timerDuration(assessment.getTimerDuration())
                        .isOptionsRandomize(assessment.isOptionsRandomize())
                        .isQuestionsRandomize(assessment.isQuestionsRandomize())
                        .createdAt(assessment.getCreatedAt())
                        .updatedAt(LocalDateTime.now())
                        .build();
                
                assessmentRepo.save(updatedAssessment);
            }
        } catch (Exception e) {
            throw new RuntimeException("Error adding question to assessment: " + assessmentId, e);
        }
    }

    /**
     * Additional utility method to remove a question from an assessment
     */
    public void removeQuestionFromAssessment(String assessmentId, String questionId) {
        try {
            Assessment assessment = assessmentRepo.findById(assessmentId)
                    .orElseThrow(() -> new RuntimeException("Assessment not found with ID: " + assessmentId));
            
            // Remove question if present
            if (assessment.getQuestionIds().contains(questionId)) {
                List<String> updatedQuestionIds = new ArrayList<>(assessment.getQuestionIds());
                updatedQuestionIds.remove(questionId);
                
                Assessment updatedAssessment = Assessment.builder()
                        .id(assessment.getId())
                        .creatorId(assessment.getCreatorId())
                        .title(assessment.getTitle())
                        .description(assessment.getDescription())
                        .questionIds(updatedQuestionIds)
                        .timerDuration(assessment.getTimerDuration())
                        .isOptionsRandomize(assessment.isOptionsRandomize())
                        .isQuestionsRandomize(assessment.isQuestionsRandomize())
                        .createdAt(assessment.getCreatedAt())
                        .updatedAt(LocalDateTime.now())
                        .build();
                
                assessmentRepo.save(updatedAssessment);
            }
        } catch (Exception e) {
            throw new RuntimeException("Error removing question from assessment: " + assessmentId, e);
        }
    }

    /**
     * Validates the CreateAssessmentRequest to ensure all required fields are present and valid
     */
    private void validateCreateAssessmentRequest(CreateAssessmentRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Assessment request cannot be null");
        }
        
        // Validate creatorId
        if (request.getCreatorId() == null || request.getCreatorId().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Creator ID cannot be null or empty");
        }
        
        // Validate title
        if (request.getTitle() == null || request.getTitle().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Title cannot be null or empty");
        }
        
        // Validate description
        if (request.getDescription() == null || request.getDescription().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Description cannot be null or empty");
        }
        
        // Validate timer duration (must be positive)
        if (request.getTimerDuration() <= 0) {
            throw new InvalidAssessmentRequestException("Timer duration must be positive (greater than 0 seconds)");
        }
    }

    /**
     * Validates the CreateQuestionRequest to ensure all required fields are present and valid
     */
    private void validateCreateQuestionRequest(CreateQuestionRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Question request cannot be null");
        }
        
        // Validate question text
        if (request.getText() == null || request.getText().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Question text cannot be null or empty");
        }
        
        // Validate question text length
        if (request.getText().length() > 1000) {
            throw new InvalidAssessmentRequestException("Question text cannot exceed 1000 characters");
        }
    }

    /**
     * Validates the CreateOptionRequest to ensure all required fields are present and valid
     */
    private void validateCreateOptionRequest(CreateOptionRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Option request cannot be null");
        }
        
        // Validate option text
        if (request.getText() == null || request.getText().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Option text cannot be null or empty");
        }
        
        // Validate option text length
        if (request.getText().length() > 500) {
            throw new InvalidAssessmentRequestException("Option text cannot exceed 500 characters");
        }
        
        // Validate question ID
        if (request.getQuestionId() == null || request.getQuestionId().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Question ID cannot be null or empty");
        }
    }

    /**
     * Validates the UpdateAssessmentRequest to ensure all required fields are present and valid
     */
    private void validateUpdateAssessmentRequest(UpdateAssessmentRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Assessment update request cannot be null");
        }
        
        // Validate assessment ID
        if (request.getAssessmentId() == null || request.getAssessmentId().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Assessment ID cannot be null or empty");
        }
        
        // Validate title
        if (request.getTitle() == null || request.getTitle().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Title cannot be null or empty");
        }
        
        // Validate description
        if (request.getDescription() == null || request.getDescription().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Description cannot be null or empty");
        }
        
        // Validate timer duration (must be positive)
        if (request.getTimerDuration() <= 0) {
            throw new InvalidAssessmentRequestException("Timer duration must be positive (greater than 0 seconds)");
        }
    }

    /**
     * Validates the UpdateQuestionRequest to ensure all required fields are present and valid
     */
    private void validateUpdateQuestionRequest(UpdateQuestionRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Question update request cannot be null");
        }
        
        // Validate question ID
        if (request.getQuestionId() == null || request.getQuestionId().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Question ID cannot be null or empty");
        }
        
        // Validate question text
        if (request.getText() == null || request.getText().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Question text cannot be null or empty");
        }
        
        // Validate question text length
        if (request.getText().length() > 1000) {
            throw new InvalidAssessmentRequestException("Question text cannot exceed 1000 characters");
        }
    }

    /**
     * Validates the UpdateOptionRequest to ensure all required fields are present and valid
     */
    private void validateUpdateOptionRequest(UpdateOptionRequest request) {
        if (request == null) {
            throw new InvalidAssessmentRequestException("Option update request cannot be null");
        }
        
        // Validate option ID
        if (request.getOptionId() == null || request.getOptionId().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Option ID cannot be null or empty");
        }
        
        // Validate option text
        if (request.getText() == null || request.getText().trim().isEmpty()) {
            throw new InvalidAssessmentRequestException("Option text cannot be null or empty");
        }
        
        // Validate option text length
        if (request.getText().length() > 500) {
            throw new InvalidAssessmentRequestException("Option text cannot exceed 500 characters");
        }
    }

    // Additional utility methods for question and option management
    
    /**
     * Get question by ID with proper response conversion
     */
    public QuestionResponse getQuestionResponseById(String questionId) {
        try {
            Question question = getQuestionById(questionId);
            return convertToQuestionResponse(question);
        } catch (Exception e) {
            throw new RuntimeException("Error fetching question: " + questionId, e);
        }
    }

    /**
     * Get option by ID with proper response conversion
     */
    public OptionResponse getOptionResponseById(String optionId) {
        try {
            Option option = getOptionById(optionId);
            return convertToOptionResponse(option);
        } catch (Exception e) {
            throw new RuntimeException("Error fetching option: " + optionId, e);
        }
    }

    /**
     * Delete question and remove it from any assessments that reference it
     */
    public void deleteQuestion(String questionId) {
        try {
            // Verify question exists
            Question question = getQuestionById(questionId);
            
            // Remove question from any assessments that reference it
            List<Assessment> assessments = assessmentRepo.findAll();
            for (Assessment assessment : assessments) {
                if (assessment.getQuestionIds().contains(questionId)) {
                    removeQuestionFromAssessment(assessment.getId(), questionId);
                }
            }
            
            // Delete all options associated with this question
            for (String optionId : question.getOptionIds()) {
                optionRepo.deleteById(optionId);
            }
            
            // Delete the question
            questionRepo.deleteById(questionId);
        } catch (Exception e) {
            throw new RuntimeException("Error deleting question: " + questionId, e);
        }
    }

    /**
     * Delete option and remove it from the question
     */
    public void deleteOption(String optionId) {
        try {
            // Verify option exists
            Option option = getOptionById(optionId);
            
            // Find the question that contains this option and remove it
            List<Question> questions = questionRepo.findAll();
            for (Question question : questions) {
                if (question.getOptionIds().contains(optionId)) {
                    List<String> updatedOptionIds = new ArrayList<>(question.getOptionIds());
                    updatedOptionIds.remove(optionId);
                    
                    // If this was the correct option, clear the correct option
                    String correctOptionId = question.getCorrectOptionId();
                    if (optionId.equals(correctOptionId)) {
                        correctOptionId = null;
                    }
                    
                    Question updatedQuestion = Question.builder()
                            .id(question.getId())
                            .text(question.getText())
                            .optionIds(updatedOptionIds)
                            .correctOptionId(correctOptionId)
                            .tags(question.getTags())
                            .build();
                    
                    questionRepo.save(updatedQuestion);
                    break;
                }
            }
            
            // Delete the option
            optionRepo.deleteById(optionId);
        } catch (Exception e) {
            throw new RuntimeException("Error deleting option: " + optionId, e);
        }
    }

    @Override
    public List<QuestionResponse> getAllQuestions() {
        try {
            List<Question> questions = questionRepo.findAll();
            return questions.stream()
                    .map(this::convertToQuestionResponse)
                    .collect(Collectors.toList());
        } catch (Exception e) {
            throw new RuntimeException("Error fetching all questions", e);
        }
    }

    @Override
    public List<OptionResponse> getAllOptionsForQuestion(String questionId) {
        try {
            Question question = getQuestionById(questionId);
            return question.getOptionIds().stream()
                    .map(this::getOptionById)
                    .map(this::convertToOptionResponse)
                    .collect(Collectors.toList());
        } catch (Exception e) {
            throw new RuntimeException("Error fetching options for question: " + questionId, e);
        }
    }

    /**
     * Enhanced method to create a complete assessment with questions and options in one go
     */
    public AssessmentResponse createCompleteAssessment(CreateAssessmentRequest assessmentRequest, 
                                                       List<CreateQuestionRequest> questionRequests,
                                                       List<List<CreateOptionRequest>> optionRequests) {
        try {
            // Create the assessment first
            AssessmentResponse assessment = createAssessment(assessmentRequest);
            
            // Create questions and options
            for (int i = 0; i < questionRequests.size(); i++) {
                CreateQuestionRequest questionRequest = questionRequests.get(i);
                QuestionResponse question = createQuestion(questionRequest);
                
                // Add question to assessment
                addQuestionToAssessment(assessment.getId(), question.getId());
                
                // Create options for this question
                if (i < optionRequests.size()) {
                    List<CreateOptionRequest> optionsForQuestion = optionRequests.get(i);
                    for (CreateOptionRequest optionRequest : optionsForQuestion) {
                        optionRequest.setQuestionId(question.getId());
                        createOption(optionRequest);
                    }
                }
            }
            
            // Return the complete assessment
            return getAssessmentById(assessment.getId());
        } catch (Exception e) {
            throw new RuntimeException("Error creating complete assessment", e);
        }
    }

